953	+ * minimal loader (`kernel/src/boot_image/elf.rs`) maps segment-by-segment into a
954	+ * fresh per-process AddrSpace. Every PT_LOAD is page-aligned (vaddr *and* file
955	+ * offset); no dynamic sections / relocations.
956	+ *
957	+ * Load base 0x0010_0000 (1 MiB): the same base every boot module uses — init
958	+ * runs in its own per-process TTBR0, so the shared base never collides. The
959	+ * stack is NOT part of the ELF: the boot loader allocates a stack frame and sets
960	+ * SP_EL0 before eret.
961	+ */
962	+
963	+OUTPUT_FORMAT(elf64-littleaarch64)
964	+OUTPUT_ARCH(aarch64)
965	+ENTRY(_start)
966	+
967	+PHDRS {
968	+    text   PT_LOAD FLAGS(5); /* R+X */
969	+    rodata PT_LOAD FLAGS(4); /* R   */
970	+    data   PT_LOAD FLAGS(6); /* RW  */
971	+}
972	+
973	+SECTIONS {
974	+    . = 0x00100000;
975	+
976	+    .text : ALIGN(4K) {
977	+        KEEP(*(.text._start))
978	+        *(.text .text.*)
979	+    } :text
980	+
981	+    . = ALIGN(4K);
982	+    .rodata : ALIGN(4K) {
983	+        *(.rodata .rodata.*)
984	+    } :rodata
985	+
986	+    . = ALIGN(4K);
987	+    .data : ALIGN(4K) {
988	+        *(.data .data.*)
989	+    } :data
990	+
991	+    .bss : ALIGN(4K) {
992	+        *(.bss .bss.*)
993	+        *(COMMON)
994	+    } :data
995	+
996	+    /DISCARD/ : {
997	+        *(.eh_frame)
998	+        *(.eh_frame_hdr)
999	+        *(.note .note.*)
1000	+        *(.comment)
1001	+        *(.dynsym .dynstr .hash .gnu.hash .dynamic)
